/**
 * An array of supported language codes for the widget.
 *
 * Supported languages:
 * - `'nl'`: Dutch
 * - `'fr'`: French
 * - `'de'`: German
 * - `'en'`: English
 */
export declare const languages: readonly ["nl", "fr", "de", "en"];
export type Language = (typeof languages)[number];
type LanguageTranslationsMap = Partial<Record<Language, RecursiveRecord>>;
export interface Translations {
    base: LanguageTranslationsMap;
    extensions: Partial<Record<string, LanguageTranslationsMap>>;
}
export interface RecursiveRecord {
    [key: string]: string | RecursiveRecord;
}
export interface ResolveOptions {
    fallback?: string;
    extension?: string;
}
export interface I18n {
    default: Language;
    translations: Translatable<RecursiveRecord>;
}
/**
 * The `Translatable<T>` type allows an object to either be a single value or a language-specific dictionary.
 * This is useful when content needs to be available in multiple languages.
 *
 * @example
 * ```typescript
 * const singleLanguageLink: Translatable<MainLink> = {
 *   label: 'Home',
 *   href: 'https://www.example.com',
 * };
 *
 * const multiLanguageLink: Translatable<MainLink> = {
 *   nl: {
 *     label: 'Startpagina',
 *     href: 'https://www.example.com/nl',
 *   },
 *   en: {
 *     label: 'Home',
 *     href: 'https://www.example.com/en',
 *   },
 *   fr: {
 *     label: 'Accueil',
 *     href: 'https://www.example.com/fr',
 *   },
 *   de: {
 *     label: 'Startseite',
 *     href: 'https://www.example.com/de',
 *   },
 * };
 *
 * globalHeaderClient.setMainLinks([singleLanguageLink]);
 * // or
 * globalHeaderClient.setMainLinks([multiLanguageLink]);
 * ```
 */
export type Translatable<T> = T | Partial<Record<Language, T>>;
export {};
